var e=JSON.parse(`[{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"성황청 비밀 서고에는 수많은 <color=#ffd34c>기적</color>이 잠들어 있다.","JPN":"聖皇庁の秘密書庫には数多くの<color=#ffd34c>奇跡</color>が眠っている。","ENG":"Countless <color=#ffd34c>Miracles</color> lie dormant in the Holy Curia's secret library.","TWN":"聖皇廳秘密書庫中沉睡著無數<color=#ffd34c>奇蹟</color>。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"관리국의 존재가 수면 위로 드러나기 전부터 교회가 수집해 온 기적의 실마리들.","JPN":"管理局の存在が明らかになる前から、教会が収集してきた奇跡の手がかり。","ENG":"They are clues that the church had been collecting long before the existence of the Administration was revealed to the public.","TWN":"在管理局的存在浮出水面之前，教會就已經收集了奇蹟的線索。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"이를테면, 소리 내어 읽은 것만으로도 배탈을 치료할 수 있다고 전해지는 마도서부터.","JPN":"たとえるなら、声に出して読んだだけでも腹痛を治癒することができると言われている魔導書から。","ENG":"For instance, there is a grimoire that can cure stomachaches just by reading its passages out loud.","TWN":"比如說，只要大聲朗讀就能治癒腹痛的魔法書。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"이를테면, 누명을 쓰고 새하얀 피를 흘리며 숨을 거둔 순교자의 유언장까지.","JPN":"濡れ衣を着せられて白色の血を流しながら息絶えた殉教者の遺言書まで。","ENG":"Or even the will of a martyr who died after being falsely accused and shedding pure white blood.","TWN":"再比如，背負冤屈，流著純白的血，臨終前的殉教者遺言。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"성황청 설립 이래로, 시성성은 수단과 방법을 가리지 않고 기적의 행방을 쫓아왔으며.","JPN":"聖皇庁の設立以来、列聖省は手段を選ばずに奇跡の行方を追跡し。","ENG":"Since the establishment of the Holy Curia, the Dicastery for the Causes of Saints has pursued the whereabouts of Miracles through any means possible.","TWN":"自聖皇廳成立以來，封聖部一直不擇手段地追尋奇蹟的蹤跡。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"또한 그 기적에 경중은 없으니…….","JPN":"また、その奇跡に軽重はない……","ENG":"Moreover, no Miracle is weighed greater or lesser than another...","TWN":"而且那奇蹟沒有輕重之分……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"따라서 비밀 서고의 사서는 있는 그대로의 기적, 그 자체를 보존할 의무가 있다.","JPN":"よって、秘密書庫の司書はありのままの奇跡、それ自体を保存する義務がある。","ENG":"Therefore, the librarian of the secret library has a duty to preserve the Miracle itself.","TWN":"因此，秘密書庫的管理員有義務將這些奇蹟原原本本地保存下來。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_09"},{"id":"L11_1","type":"narration","speaker":null,"text":{"KOREA":"때때로, 그 기적이 아무리 사소하고 보잘것없어 보일지라도.","JPN":"時にその奇跡がとても小さく些細なものに見えたとしても。","ENG":"At times, they may seem insignificant.","TWN":"有時候，那些奇蹟看起來微不足道。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"때때로, 그 기적이 세상에서 완전히 지워버리고 싶을 정도로 낯부끄러운 것일지라도.","JPN":"時にその奇跡がこの世から完全に消しさりたいほど不名誉なことであるとしても。","ENG":"At other times, they are embarrassing to the point one wishes to completely erase the Miracles from the world.","TWN":"有時候，那些奇蹟甚至會讓人羞愧到想要將其徹底從世界上抹去。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"narration","speaker":null,"text":{"KOREA":"주께서 사서에게 부여하신 의무는 기적의 보존이지, 결코 말소가 아닐 터.","JPN":"主が司書に与えられし義務は奇跡の保存であり、決して抹消ではない。","ENG":"Nevertheless, the duty given to the librarian by the Lord is to preserve, not destroy.","TWN":"但主賦予管理員的職責是保存奇蹟，絕不是抹除。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"그렇기에…….","JPN":"そのため……","ENG":"And so...","TWN":"正因為如此……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"주여.","JPN":"主よ。","ENG":"Oh, Lord.","TWN":"主啊。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신의 어린 양이 고해성사의 기도를 올립니다.","JPN":"子羊が告解の祈りを捧げます。","ENG":"I offer a prayer of confession.","TWN":"你的小羊正在懺悔祈禱。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"narration","speaker":null,"text":{"KOREA":"그렇기에 여기 한 젊은 사서가 고민에 빠졌다.","JPN":"そのためここに、1人の若い司書が悩んでいる。","ENG":"One young librarian finds herself in deep contemplation.","TWN":"因此，這裡有一位年輕的圖書管理員陷入了困境。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"그녀가 손에 넣은 것은 어느 디저트의 <color=#ffd34c>레시피</color>.","JPN":"彼女が手に入れたのは、あるデザートの<color=#ffd34c>レシピ</color>。","ENG":"She has in her hands a certain dessert <color=#ffd34c>recipe</color>.","TWN":"她得到的是某種甜點的<color=#ffd34c>食譜</color>。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"narration","speaker":null,"text":{"KOREA":"그것은 어쩌면 기적을 향한 실마리가 될지도 모르는 것.","JPN":"それはもしかしたら、奇跡への手がかりとなり得るかもしれないもの。","ENG":"Perhaps this, too, could be a clue to a Miracle.","TWN":"那或許是通往奇蹟的線索。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"주여.","JPN":"主よ。","ENG":"Oh, Lord.","TWN":"主啊。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L24_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"어째서 저를 시험에 들게 하십니까…….","JPN":"私を試さないでください……","ENG":"Why do You lead me into temptation...?","TWN":"為什麼要考驗我……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"narration","speaker":null,"text":{"KOREA":"평소처럼 냉철한 이성과 신앙심으로 기적의 보존을 행사할 것인지.","JPN":"いつもどおりに冷徹な理性と信仰で奇跡の保存を行うか。","ENG":"Will she continue to preserve the Miracle with her collected reason and faith?","TWN":"是否能像往常一樣，憑藉冷靜的理性和信仰來保存奇蹟。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"narration","speaker":null,"text":{"KOREA":"사사로운 감정으로 자신이 목도한 기적을 부정하고, 자신의 손으로 말살할 것인지.","JPN":"私情で自分が目撃した奇跡を否定し、自分の手で抹殺するか。","ENG":"Or will she deny the Miracle she has witnessed out of personal feelings and destroy it herself?","TWN":"是否會因私慾而否定自己目睹的奇蹟，並親手將其抹除。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"주여.","JPN":"主よ。","ENG":"Oh, Lord.","TWN":"主啊。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L28_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"부디 부덕한 저를 용서하여 주옵소서.","JPN":"どうか、不徳な私をお許しください。","ENG":"Please forgive my being unscrupulous.","TWN":"請你原諒我這個罪人。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"narration","speaker":null,"text":{"KOREA":"그 날. 새하얀 눈으로 뒤덮인 성야의 날.","JPN":"あの日。純白の雪で覆われた聖夜の日。","ENG":"That holy night, when the world was covered in pure white snow.","TWN":"那一天，被潔白的雪覆蓋的平安夜。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"narration","speaker":null,"text":{"KOREA":"그 거룩한 밤에 일어난 기적의 행방은 오롯이 이 젊은 사서의 손에 달려 있으니…….","JPN":"あの聖なる夜に起きた奇跡の行方は、まさにこの若い司書の手にかかっている……","ENG":"The Miracle that occurred on that holy night lies solely in the hands of this young librarian...","TWN":"那神聖之夜發生的奇蹟，全都掌握在這位年輕的管理員手中……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"narration","speaker":null,"text":{"KOREA":"성무 코드 <color=#ffd34c>X12MAS25</color>.","JPN":"聖務コード<color=#ffd34c>X12MAS25</color>。","ENG":"Sacred Mission Code <color=#ffd34c>X12MAS25</color>.","TWN":"聖務代碼<color=#ffd34c>X12MAS25</color>。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"narration","speaker":null,"text":{"KOREA":"통칭, <color=#ffd34c>성야의 쇼콜라 무스 케이크 사건</color>.","JPN":"通称、<color=#ffd34c>聖夜のムースショコラ事件</color>。","ENG":"A.K.A, <color=#ffd34c>The Holy Night Chocolate Mousse Cake Incident</color>.","TWN":"統稱，<color=#ffd34c>平安夜巧克力慕斯事件</color>。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"narration","speaker":null,"text":{"KOREA":"모든 것은, 그 달콤하고도 끔찍한 디저트로부터 시작되었다.","JPN":"すべては、その甘く残酷なデザートから始まった。","ENG":"It all started from that sweet yet horrendous dessert.","TWN":"一切都始於那道甜美又可怕的甜點。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>사건</color> 보름 전","JPN":"<color=#ffd34c>事件</color>の2週間前","ENG":"2 weeks before <color=#ffd34c>the incident</color>","TWN":"<color=#ffd34c>事件</color> 發生半個月前"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>성황청</color> 기적심의회 제9본부","JPN":"<color=#ffd34c>聖皇庁</color>奇跡審議会第9本部","ENG":"<color=#ffd34c>Holy Curia</color> Miracle Investigation Council 9's HQ","TWN":"<color=#ffd34c>聖皇廳</color> 奇蹟議會第9總部"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"하늘에 계신 우리 아버지…….","JPN":"天にまします我らの父よ……","ENG":"Our Father, Who art in heaven...","TWN":"天上的父親……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"아버지 이름이… 거룩히 빛나시며…….","JPN":"願わくは……御名の尊まれんことを……","ENG":"Hallowed be... Thy name...","TWN":"父親的名字……神聖地閃耀著……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"계속하세요.","JPN":"続けてください。","ENG":"Please, continue.","TWN":"繼續吧。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"으음, 아버지의 나라가 오시며, 아버지의 뜻이… 하늘에서와 같이…… 하늘과 같아서…….","JPN":"うーん、御国の来らんことを、御旨の……天に行わるる如く……天のように……","ENG":"Erm, Thy kingdom come... Thy will be done... on earth... On earth...","TWN":"嗯，願父親的旨意行在地上，如同行在天上一樣……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"하늘과 같아서…… 우러러 볼수록 높아만 지네……!","JPN":"天のようで……仰げば仰ぐほど高くなりて……！","ENG":"As it is in the sea... where the waves roll gently for all to see...!","TWN":"如同天空……越仰望越高……！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L49_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"이거 맞지?","JPN":"合ってるよね？","ENG":"I got it! Right?","TWN":"你確定是這個嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"아얏……!","JPN":"痛っ……！","ENG":"Oww...!","TWN":"啊呀……！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L3_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"짐작하고는 있었지만, 한심해서 말이 안 나올 지경이로군요.","JPN":"そんなことだろうとは思っていましたが、情けなくて言葉も出ません。","ENG":"I expected such, but I am still baffled by your stupidity.","TWN":"雖然有所預料，但實在是太可笑了，簡直無話可說。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"지금껏 교회에 적을 두고 있었으면서, 이런 기초적인 기도조차 외우지 못하는 건가요?","JPN":"今まで教会に所属していたのに、このような基本的な祈りさえ覚えられないのですか？","ENG":"You have been at the church all this time, but why is it that you have not even memorized the basic prayers?","TWN":"一直在教會裡，卻連這種基本的祈祈禱文都不會背嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"칫, 기도 같은 게 다 무슨 소용이야?","JPN":"ちっ、祈りなんて何の役にも立たないし。","ENG":"Tch, what good do prayers even do?","TWN":"哼，祈禱什麼的有什麼用？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"그깟 기도문 좀 잘 외운다고 침식체들이 평소보다 살살 때리기라도 한데?","JPN":"そんなもの覚えても、侵食体がいつもより弱くなるとかでもないでしょ？","ENG":"If I pray, do the C.O.s hit me more gently?","TWN":"就算背誦那些祈祈禱文，侵蝕體會比平時打得輕一點嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"아얏! 우씨이! 지금 해보자는 거지?","JPN":"いたっ！　ちょっと！　ケンカ売ってる？","ENG":"Oww! Hey! You wanna have a go at me?","TWN":"哎唷！可惡！你現在是要找我碴是吧？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L9_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"우리의 사명은 어디까지나 침식으로부터 주님의 어린 양을 구제하는 것.","JPN":"私たちの使命は、あくまでも侵食から主の子羊たちを救済すること。","ENG":"Our duty is to save the Lord's flock from the Corruption.","TWN":"我們的使命始終是從侵蝕中拯救主的小羊。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"고삐 풀린 망아지처럼 날뛰는 게 전부가 아니라고 누누이 말씀드렸을 텐데요?","JPN":"子馬のように暴れるのがすべてではないと言っていたはずです。","ENG":"Have I not told you several times already that running wild like a colt without reins is not your job?","TWN":"我不是早就說過了嗎？不能像脫韁的野馬一樣亂跑！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"까먹었다, 어쩔래?","JPN":"忘れたんだけど、何か？","ENG":"I forgot. What are you gonna do about it?","TWN":"我忘了，怎樣？！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"칫, 누가 꼰대 아니랄까 봐, 앞뒤 꽉 막혀가지고.","JPN":"ちっ、眼鏡ばばあ。頭固すぎ。","ENG":"Tch, you're such a snob. So anal about everything.","TWN":"嘖，怕人家不知道你是老古板的四眼田雞嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"꺽다리가 우린 그냥 침식체만 잘 썰면 된다고 했단 말이야.","JPN":"のっぽが、アタシたちは侵食体さえやっつけられればいいって言ってたんだよ。","ENG":"Long Legs said that all we need to do is defeat C.O.s.","TWN":"高個子說我們只需要好好解決侵蝕體就行了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"글쎄요. <color=#ffd34c>사제 심사</color>를 감독할 주교들은 이보다 더하면 더했지 덜하지는 않을 겁니다.","JPN":"どうでしょう。<color=#ffd34c>司祭審査</color>を監督する司教は、私より頭が固いはずです。","ENG":"Well. The bishops in charge of the <color=#ffd34c>priest evaluation</color> will be stricter than me.","TWN":"這個嘛。<color=#ffd34c>神職考核</color>的主教們只會更加嚴格，一點都不會鬆懈。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"무엇보다도…….","JPN":"なにより……","ENG":"Above all else...","TWN":"但最重要的是……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"다른 주교들 앞에서는 <color=#ffd34c>그 자</color>에 대한 언급을 금하도록 하세요.","JPN":"他の司教の前では<color=#ffd34c>あの人</color>を口にしないように気をつけてください。","ENG":"please refrain from mention <color=#ffd34c>that man</color> in front of the other priests.","TWN":"在其他主教面前禁止提及<color=#ffd34c>那個人</color>。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"제 손으로 직접 당신을 심판하게 될지도 모르니까요.","JPN":"私の手で直接あなたを審判することになるかもしれません。","ENG":"For I might have to bring down judgment myself if you do.","TWN":"否則說不定我會親自審判你。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"흥. 그거 듣던 중 반가운 소리네. 누가 겁낼 줄 알고?","JPN":"フン。それはいいね。全っ然怖くないし。","ENG":"Hmph. You couldn't have said it better. You think that will scare me?","TWN":"哼，這可是我聽過最令人高興的消息了，你以為我會怕嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"}}}},{"id":"L22_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"시스터 루퍼, 당신에 관해서는 전부 읽었습니다.","JPN":"シスター・ルーパー、あなたに関する資料は全部読みました。","ENG":"Sister Looper, I have read everything about you.","TWN":"洛珀姊妹，我已經了解關於你的一切了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이미 지난 두 차례의 사제 심사에서 불합격 판정을 받은 이력이 있더군요.","JPN":"2度の司祭審査で不合格判定された履歴があったようですね。","ENG":"I noticed that you have failed to pass the priest evaluation twice already.","TWN":"已經有兩次在神職考核未通過的記錄了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"그래서 뭐?","JPN":"だから、なに？","ENG":"So, what?","TWN":"所以呢？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"기록에 따르면, 심사를 진행하던 주교의 귀를 물어뜯었다고 하던데… 사실인가요?","JPN":"記録によると、審査を監督していた司教の耳を噛みちぎったとか……事実ですか？","ENG":"According to the records, you bit off the priest's ear off during your evaluation... Is this true?","TWN":"根據記錄，你咬掉了負責考核的主教的耳朵……是真的嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"그건 그 할아범이 먼저 잘못한 거야.","JPN":"それはあのジジイが悪いんだよ。","ENG":"That's because that geezer did me wrong first.","TWN":"是那個老頭子先做錯了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"아무런 이유 없이 이교도의 자식이라면서 대놓고 씹어대는데 뭐 어쩌겠어?","JPN":"なんの理由もなく異教徒の子どもだって罵ってくるから、仕方ないじゃん？","ENG":"What else was I supposed to do when that jerk kept criticizing me about being a pagan child for no reason?","TWN":"無緣無故地說我是異教徒的孩子，公然詆毀我，我能怎麼辦？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"씹어줄 이유를 하나 만들어 줄 수밖에.","JPN":"だから罵れるそれなりの理由を作ってやったんだよ。","ENG":"So, I gave him a reason.","TWN":"這就是我咬他的理由。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"아무런 이유도 없다라…? 기꺼이 정정해 드리죠.","JPN":"なんの理由もなく、ねえ……？　喜んで訂正いたします。","ENG":"No reason, you say... I would be more than happy to rephrase.","TWN":"不是毫無理由嗎……？那請容我更正一下。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"작성된 경위서에는 미사 진행 중, 성체 대신 풍선껌을 씹었다고 쓰여있더군요.","JPN":"作成された経緯書にはミサの途中、聖体の代わりにガムを噛んでいたと書かれていますが。","ENG":"The report states that you were chewing on bubblegum instead of the communion during mass.","TWN":"在始末報告中，寫著在你望彌撒的過程中，嚼了口香糖來代替聖體。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"아. 난 그 밀가루 반죽만 씹으면, 속이 니글거리거든.","JPN":"ああ。アタシ、あの小麦粉の生地食べるとお腹痛くなるの。","ENG":"Oh. That's because my stomach gets upset whenever I chew that dough.","TWN":"啊，我一咬到那個麵團就反胃想吐。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"뭐 어때? 어차피 마음이 중요한 거라면서?","JPN":"だからってなに？　どうせ気持ちが重要なんでしょ？","ENG":"Who cares? They say that it's the heart that counts.","TWN":"那又怎樣？反正心意最重要，不是嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"그럼, 상관없잖아. 남이사 반죽을 씹든, 껌을 씹든, 귀를 씹든…….","JPN":"なら関係ないじゃん。生地を噛もうが、ガムを噛もうが、耳を噛もうが……","ENG":"So, it doesn't matter if I chew on dough, gum, or that jerk's ear–","TWN":"所以，無所謂吧。管它是嚼麵團、嚼口香糖、還是嚼耳朵的……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"아야야……!","JPN":"いたた……！","ENG":"Owwww...!","TWN":"啊呀呀……！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그 자리에서 파문당하지 않았던 게 용할 지경이네요.","JPN":"その場で破門されていなかったのが奇跡ですね。","ENG":"I am surprised that you were not excommunicated on the spot.","TWN":"沒當場把你逐出教堂算你好運。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"이씨! 대체 뭐가 문제야? 그깟 심사가 그렇게 중요해?","JPN":"ちょっと！　何がいけないの？　あの審査がそんなに重要？","ENG":"Hey! What's your problem? What's so important about that evaluation?","TWN":"可惡！到底有什麼問題？那種考核有那麼重要嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L43_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"그거 통과한다고 지금껏 없었던 신앙심이 막 솟아나기라도 하냐고.","JPN":"それに合格したからって今までなかった信仰心が湧き出るわけでもないじゃん。","ENG":"Do you really think passing that test will suddenly make me super religious?","TWN":"通過那個就會突然湧現出前所未有的信仰嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"난 침식체만 썰어버릴 수 있으면, 다른 건 아무래도 상관없거든?","JPN":"アタシは侵食体さえやっつけられれば、他はどうでもいいんだよ。","ENG":"I don't care about anything as long as I can cut up C.O.s, okay?","TWN":"只要能砍掉侵蝕體，其他的我都無所謂！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"}}},"sfx":"FX_COMBAT_ALL_CHAINSAW_ATTACK_SMALL"},{"id":"L45_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"확실히. 당신에게 정상적인 신앙심 같은 걸 기대하는 사람은 아무도 없었겠죠.","JPN":"確かに。あなたにまともな信仰心などを期待している人は誰もいないでしょう。","ENG":"Surely. I suppose no one ever expects you to have any kind of genuine faith.","TWN":"確實，沒有人會期待你有正常的信仰。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하지만 이제 상황이 달라졌습니다.","JPN":"ですが、今は状況が変わりました。","ENG":"However, the situation has changed.","TWN":"但是現在情況變了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"무슨 소리야?","JPN":"どういうこと？","ENG":"What do you mean?","TWN":"什麼意思？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"모든 것은 베네딕트 콘스탄틴…….","JPN":"すべてはベネディクト・コンスタンティン……","ENG":"This is all because of Benedict Constantine...","TWN":"所有的一切都是康斯坦丁……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L50_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그리고 기적심의회 의장 요한 추기경께서 불미스러운 일로 서거하셨기 때문입니다.","JPN":"そして奇跡審議会の議長であるヨハン枢機卿が、芳しくない事件で逝去されたからです。","ENG":"And Cardinal Johan, Chairman of the Miracle Investigation Council, passed away under unfortunate circumstances.","TWN":"而且奇蹟議會議長約翰樞機主教因不幸事件去世了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"<color=#ffd34c>천사는 가까이. 하지만 사탄은 더 가까이.</color>","JPN":"<color=#ffd34c>天使と親しく。だが悪魔にはもっと親しく。</color>","ENG":"<color=#ffd34c>Keep angels close. But the devil closer.</color>","TWN":"<color=#ffd34c>離天使近一點……離撒旦更近一點……</color>"},"stage":{"bg":"VATICAN_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"기적심의회는 성황청의 대침식 전문 기관입니다.","JPN":"奇跡審議会は聖皇庁の対侵食専門機関です。","ENG":"The Miracle Investigation Council is Holy Curia's anti-Corruption institution.","TWN":"奇蹟議會是聖皇廳專門對抗侵蝕體的機關。"},"stage":{"bg":"VATICAN_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그 조직의 특성 상, 심의회는 대침식전에 유리한 카운터를 우선적으로 선별해왔죠.","JPN":"その組織の特性上、審議会は対侵食戦で有利なカウンターを優先して選抜してきたのです。","ENG":"Due to the special nature of the organization, the Investigation Council prioritized recruiting Counters who are better at anti-C.O. warfare.","TWN":"由於組織的特性，議會一直以來都會優先挑選適合投入侵蝕戰的制裁者。"},"stage":{"bg":"VATICAN_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"다시 말해, 예하께서는 출신 성분과 성직자로서의 인격이나 자질…….","JPN":"つまり、猊下は出身と聖職者としての人格や資質……","ENG":"In other words, His Eminence chose those who could fight immediately for the Lord...","TWN":"換句話說，不用看你的出身履歷和神職人員的品格或素質……"},"stage":{"bg":"VATICAN_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하물며 신앙심보다도 주님을 위해 당장 싸울 수 있는 자들을 선택해왔다는 뜻입니다.","JPN":"まして信仰心より、主のために今すぐにでも戦える者たちを選んできたという意味です。","ENG":"prioritizing one's ability over one's background, character, faith, and even one's qualifications as a priest.","TWN":"意思就是，信仰不是最重要的，最重要的是能否立刻成為戰力，為主而戰。"},"stage":{"bg":"VATICAN_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"덕분에 심의회는 비교적 일찍 관리국 태스크포스 라이선스를 획득할 수 있었지만.","JPN":"おかげで審議会は比較的早く管理局のタスクフォースライセンスを獲得できたのですが。","ENG":"Thanks to that, the Investigation Council was able to obtain the Administration's TASKFORCE license relatively early.","TWN":"多虧於此，議會才能比較早地獲得管理局特遣勢力執照。"},"stage":{"bg":"VATICAN_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"한편, 대외적으로 아주 유명한 별명을 갖게 되었죠.","JPN":"一方、対外的にとても有名な異名を持つことになりました。","ENG":"But on the other hand, we also gained an infamous nickname as well.","TWN":"另一方面，他們在外界有一個非常有名的綽號。"},"stage":{"bg":"VATICAN_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"<color=#ffd34c>주님의 미친개들</color>…….","JPN":"<color=#ffd34c>主の狂犬たち</color>……","ENG":"<color=#ffd34c>Mad Dogs of the Lord</color>...","TWN":"<color=#ffd34c>天主的走狗</color>……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"잠깐.","JPN":"待って。","ENG":"Wait.","TWN":"等一下。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"듣자 하니, 지금 그거 내 얘기하는 거야?","JPN":"今の話、それってアタシのこと？","ENG":"Come to think of it, this is about me, isn't it?","TWN":"聽上去，現在你是在說我的事嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그렇습니다. 다행히 눈치라는 게 있긴 하군요, 하룻강아지.","JPN":"そうです。幸い空気は読めるのですね、子犬。","ENG":"Correct. At least you still have some sense, little one.","TWN":"沒錯，幸好你還有點自覺，小奶狗。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"하룻강아지? 그거 칭찬 아닌 거 같은데.","JPN":"子犬？　それ褒めてないでしょ。","ENG":"Little one? I don't think that was a compliment.","TWN":"小奶狗？這不是在誇我吧？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"……시스터 루퍼.","JPN":"……シスター・ルーパー。","ENG":"...Sister Looper.","TWN":"……洛珀姊妹。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신이 심의회에 가장 잘 어울리는 인재라는 건 누구도 부정할 수 없겠죠.","JPN":"あなたが審議会にもっとも相応しい人材であるということは、誰も否定できないはずです。","ENG":"There is no denying that you are a crucial asset to the Investigation Council.","TWN":"沒人能否認你是最適合議會的人才。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하지만 성황청에는 당신 같은 존재를 불쾌히 여기는 자들도 얼마든지 있습니다.","JPN":"ですが、聖皇庁にはあなたのような存在を不快に思っている者もいくらでもいる。","ENG":"However, keep in mind that there are people who are displeased by the likes of you here.","TWN":"但是在聖皇廳裡，也有很多人對像你這樣的存在感到不快。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"결국, 당신이 이단 공동체의 마지막 생존자라는 사실은 달라지지 않을 테니까요.","JPN":"結局、あなたが異端共同体の最後の生存者であるという事実は変わらないでしょうから。","ENG":"In the end, the fact that you are the last survivor of a pagan community will never change.","TWN":"最終，你仍然是異端共同體的最後倖存者，這一點不會改變。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"거 참, 미안하게 됐수다.","JPN":"それはまあ、悪かったね。","ENG":"Ugh, I'm sorry. Happy?","TWN":"真是的，怪我囉？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"그래서 나보고 뭐 어쩌라고. 얼굴도 모르는 엄마 뱃속으로 다시 들어가란 소리야?","JPN":"で？　アタシにどうしろって言うんだよ。顔もわからないお母さんの腹の中に戻れって？","ENG":"What do you want me to do? Should I crawl back into my faceless mother's womb?","TWN":"所以你讓我怎麼辦？讓我回到我從未見過的媽媽的肚子裡嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"심의회는 그동안 성황청 내부 불만의 목소리를 성과만으로 눌러왔습니다.","JPN":"審議会は今まで聖皇庁内部の不満の声を成果だけで抑えてきました。","ENG":"The Investigation Council has suppressed the disgruntled voices of Holy Curia by providing meaningful results.","TWN":"審議會一直以來都用成績壓制聖皇廳內部不滿的聲音。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하지만 그런 불미스러운 사건이 발생했으니, 성황청이 직접 나서려고 하겠죠.","JPN":"ですがあんな不祥事が発生したからには、聖皇庁が直接動こうとするでしょう。","ENG":"But since such an unfortunate incident has occurred, Holy Curia will take direct action.","TWN":"但是發生了那樣的不幸事件，聖皇廳應該會親自出面吧。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"조만간 이를 명분으로 대대적인 감사를 진행할 겁니다.","JPN":"近いうち、これを口実に大々的な監査が行われるはずです。","ENG":"Soon, they'll conduct a large-scale audit under this pretext.","TWN":"不久之後，將以此為名進行大規模的監察行動。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"감사라고? 뭐가 감사하다는 거야?","JPN":"かんさ？　なにそれ、食べ物？","ENG":"An audit? What kind of audition are they holding?","TWN":"檢查？有什麼好檢查的？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L36_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"뭐, 집행 사제로서 제 역할을 다하고 있는 대다수의 인원은 큰 문제가 없겠죠.","JPN":"まあ、執行司祭として自分の役割を果たしているほとんどの人には大した問題ではないでしょう。","ENG":"Well, I believe it will not be an issue to the majority of those who are doing their duty as an Inquisitorial Priest.","TWN":"嗯，作為治理祭司，大多數人都在盡職盡責，應該沒什麼大問題。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하지만 사제 심사에서 두 번이나 떨어진 어느 구제불능 시스터는 이야기가 다릅니다.","JPN":"ですが司祭審査で2度も不合格した、救いようのないシスターにとっては話が違います。","ENG":"But for a hopeless Sister who has failed the priest evaluation twice, it will be different.","TWN":"但是對於在神職考核中兩次落選的，某個無可救藥的修女，情況就不一樣了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"자, 슬슬 사태가 얼마나 심각한지 짐작하셨나요?","JPN":"さて、そろそろどんなに深刻な事態なのかわかってきましたか？","ENG":"Now, do you realize how serious the situation is?","TWN":"那，這樣你可以明白事態有多嚴重了吧？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"보조 사제 신분으로 그간 적당히 넘겨왔지만, 이번 심사는 반드시 통과해야 할 겁니다.","JPN":"今までは補助司祭として適当に誤魔化してきたのですが、今回の審査は必ず合格しないといけません。","ENG":"You might have been cut some slack as an apprentice priest, but you must pass the evaluation this time.","TWN":"雖然之前一直拿你還不是正式的祭司當作藉口蒙混過關，但你必須通過這次的考核。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"주님의 어린 양을 구제하는 시스터가 사실 기도문조차 외우지 못한다는 걸, 성황청이 알게 된다면…….","JPN":"主の子羊を救済するシスターが、実は祈祷文さえ覚えていないということを聖皇庁が知ったら……","ENG":"If Holy Curia found out that one of their Sisters cannot even memorize prayers...","TWN":"如果聖皇廳發現這位拯救主的小羊的修女竟然連祈祈禱文都不會背……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"심의회는 틀림없이 <color=#ffd34c>파국</color>을 맞이하게 될 테니까요.","JPN":"審議会は間違いなく、<color=#ffd34c>破局</color>を迎えることになるでしょうから。","ENG":"the Investigation Council will undoubtedly face its <color=#ffd34c>demise</color>.","TWN":"奇蹟議會肯定會迎來<color=#ffd34c>死局</color>的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L46_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"으음…….","JPN":"うーん……","ENG":"Mm...","TWN":"嗯……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"안경 꼰대, 뭐 하나만 물어봐도 돼?","JPN":"眼鏡ばばあ、一つ聞いてもいい？","ENG":"Specky Snob, can I ask you something?","TWN":"四眼姊姊，可以問你一個問題嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"훗, 이제야 비로소 성경 공부를 할 마음이 생긴 모양이로군요.","JPN":"ふっ、やっと聖書の勉強をする気になったようですね。","ENG":"Hmm, it seems you have finally found the will to study the Bible.","TWN":"哼，現在終於有心情學習聖經了吧。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"좋습니다. 배움에 목마른 이를 외면하지 않는 것 또한 주의 뜻.","JPN":"いいでしょう。何かを学ぼうとする者から目を背けないのもまた主の意志。","ENG":"Very well. It is also the will of the Lord not to turn away those who wish to learn.","TWN":"好的，不忽視渴望學習的人也是主的旨意。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"기꺼이 당신을 조신한 시스터로 만들어드리죠.","JPN":"喜んであなたを慎ましいシスターにしてあげましょう。","ENG":"I will happily make you into a respectable Sister.","TWN":"我會幫助你成為一位合格的修女的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"자, 무엇이든 물어보세요. 시스터 루퍼.","JPN":"さあ、なんでも聞いてください。シスター・ルーパー。","ENG":"Now, ask away, Sister Looper.","TWN":"來吧，什麼都可以問，洛珀姊妹。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"파국이 뭐야?","JPN":"はきょくってなんだ？","ENG":"What's a \\"demise\\"?","TWN":"什麼是死局？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L8_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"과연, 쉽지 않은 성무가 되겠군요.","JPN":"なるほど、厳しい聖務になりそうですね。","ENG":"I see. This will be a difficult sacred duty I must uphold.","TWN":"此次的聖務實屬不易呢。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};